var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"도플갱어 그림자 휘하의 잔챙이들은 우리가 맡는다!","JPN":"ドッペルゲンガーシャドウに操られている雑魚どもはこっちが片付ける！","ENG":"We will deal with the small C.O.s under the Doppelganger Shadow's command!","TWN":"這些二重身暗影控制的小嘍囉就交給我們了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"야크샤 전대가 도플갱어의 상대에 집중할 수 있도록 길을 여는 거다!!","JPN":"ヤクシャー戦隊がドッペルゲンガーとの戦いに集中できるよう、道を開くのだ！","ENG":"Open the way for the Yaksha Division to solely focus on the Doppelganger!","TWN":"為夜叉戰隊與二重身單獨對戰提供機會！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"흥! 성가시네!","JPN":"ふん！　厄介ね。","ENG":"Hmph! How annoying!","TWN":"哼！真是麻煩！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어차피 가축만도 못한 복제 인간들 주제에! 가소롭긴!","JPN":"家畜以下の複製人間どものくせに、小賢しい！","ENG":"You're all clones who are no better than livestock! It's laughable!","TWN":"連畜生都不如的複製人！真是可笑！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"반항하지 말고, 얌전히 내 선율에 복종하란 말이야!","JPN":"大人しく降参して、私の旋律に服従しなさい！","ENG":"Stop resisting and succumb to my melody!","TWN":"停止反抗，乖乖服從我的旋律吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어딜……!!","JPN":"させないぞ！！","ENG":"Not a chance...!","TWN":"看招……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"큭! 감히 내 연주를 방해하다니……!","JPN":"くっ……！　私の演奏を邪魔するなんて……！","ENG":"Kgh! How dare you interrupt my performance...?!","TWN":"咳！你竟敢干擾我的表演……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗! 아니, 오히려 기회일까나?","JPN":"いいえ、むしろチャンスかしら。ふふっ……！","ENG":"Fu fuu! No, perhaps this is an opportunity?","TWN":"呵呵呵！不，這不正是個好機會嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"읏……!?","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"呃……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"……츄릅.","JPN":"……チュッ。","ENG":"...*Slurp*","TWN":"……嘶。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아아, 나의 원본이라서 그런지, 피 맛이 감미롭네.","JPN":"ああ、さすが私のオリジナル。血の味も美味だわ。","ENG":"Ah, is it because you're my original? But even your blood tastes sweet.","TWN":"啊，我本體的鮮血，味道如此甜美。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제기랄, 진짜 고양이처럼 할퀴어 댈 줄이야.","JPN":"くそ、本物の猫みたいにひっかきやがった。","ENG":"Dammit. I didn't think she'd claw me like a real cat.","TWN":"該死的，竟然真的像貓一樣抓我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗, 하지만 이래서는 허기만 지겠어.","JPN":"うふふっ、でもこれじゃ空腹を刺激するだけだわ。","ENG":"Fu fuu, but this will only make me hungrier.","TWN":"呵呵呵，這只會讓我更餓。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그래……! 일단 원본인 너부터 잡아먹으면 다른 잔챙이들은……!","JPN":"そうね……！　まずはオリジナルの君から喰べたら、他の奴らは……！","ENG":"Yes...! I'll consume the original first, then take care of the rest–!","TWN":"就是這樣……！先從本體吃起，然後是其他配菜……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나를 잊어버리다니 섭섭한데?","JPN":"私を忘れてくれちゃ困るよ？","ENG":"Have you forgotten about me? How disappointing.","TWN":"已經忘了我嗎？真令人失望。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"흥! 맞추지도 못하는 게 촐랑촐랑 뛰어다니긴……!!","JPN":"ふん、まともに当てられないくせに、ぴょんぴょん飛び跳ねて……！！","ENG":"Hmph! How about you stop hopping around? You can't even hit me once...!","TWN":"哼！你唯一讓我火大的地方就是到處亂跑……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"크윽, 얼음 때문에 성가시네……!","JPN":"ちっ、氷が目障りね……！","ENG":"Kgh, these icicles are getting on my nerves...!","TWN":"呃，煩人的冰塊……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그런데 어쩌나?","JPN":"ところでどうかしら。","ENG":"Unfortunately for you...","TWN":"但那又怎樣？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아직 나에게 복종하는 아이들이 남았거든……!!","JPN":"まだ私に服従している子どもたちがいるのよね……！！","ENG":"I still have some grunts that'll obey my command...!!","TWN":"這些孩子還聽我的話呢……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"쓰러졌던 침식체들이 다시 일어나고 있어!","JPN":"倒れてた侵食体が立ち上がっている！","ENG":"The fallen C.O.s are getting back up!","TWN":"擊倒的侵蝕體又起來了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아무래도 침식체들을 회복시키는 게 저 그림자의 고유한 능력인가 보네.","JPN":"どうやら、侵食体を回復させるのがあのシャドウの固有能力のようね。","ENG":"I assume that healing C.O.s is that Shadow's unique ability.","TWN":"看來那個暗影的獨特能力是治療侵蝕體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하여간 엘리시움 녀석들은 성가시다니까.","JPN":"まったく、これだからエリシウムのやつらは厄介なのよ。","ENG":"Those Elysium Shadows are always such a pain to deal with.","TWN":"這些樂團的傢伙真是煩人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그럼 어떻게 해야 되는데? 뭔가 대책이라도 있어?","JPN":"じゃ、じゃあどうすれはいいんだ？　何か対策はないのか？","ENG":"Th-then what do we do? Do you have a plan?","TWN":"呃，那我們該怎麼辦呢？有什麼解決辦法嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 어떻게 하면 되냐고?","JPN":"ええと、どうすればいいのかって言うとね。","ENG":"Hmm? Do I have a plan?","TWN":"嗯，該怎麼辦嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이제 기다리기만 하면 돼.","JPN":"待つだけでいいの。","ENG":"We just have to wait now.","TWN":"現在要做的就是等待。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐라고?","JPN":"はあ？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"자, 그럼 이제 내 비장의 연주를 시작해볼까?","JPN":"それじゃあ、とっておきの演奏を始めようかしら？","ENG":"Now, the time has come for me to perform my masterpiece!","TWN":"現在，請欣賞我的傑作！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"크, 크윽……!! 몸이……!!","JPN":"く、くうっ……！！　体が……！！","ENG":"K-kgh...! My body...!!","TWN":"呃……呃……！！身體……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"몸이 움직이지 않아……!! 어째서……!?","JPN":"体が動かない……！！　なぜ……！？","ENG":"Why can't I move it...?! What's happening...?!","TWN":"身體動不了了……！！為什麼……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗, 그러니까 처음부터 저항하지 않았으면 얼마나 좋아?","JPN":"うふふ、だから最初から諦めればよかったのに。","ENG":"Fu fuu, see? How easier would've this been for you if you didn't resist?","TWN":"呵呵呵，所以一開始就不要反抗多好？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"얌전히 나한테 먹혀서 하나가 되었으면…… ","JPN":"大人しく私に喰われて、一つになれば…… ","ENG":"Now, after I consume you and become one...","TWN":"老老實實地讓我吃掉融為一體吧……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"唔？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_INJECTOR"},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"콘트라베이스의 현이…… 끊어졌어……?","JPN":"コントラバスの弦が……切れている……？","ENG":"My contrabass's string... snapped...?","TWN":"低音提琴的弦……斷了……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아니야……. 현을 쥐고 있던 손가락이 갑자기 떨어졌어……!","JPN":"違う……弦を抑えていた指が切れたんだわ……！","ENG":"No... My finger that I was holding the string with suddenly fell off...!","TWN":"不……我的手指怎麼也……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"잠깐, 내 다리가……? 감각이……?","JPN":"待って、足が……感覚が……？","ENG":"Wait, my legs... Why can't I feel them...?","TWN":"等一下，我的腿……？為什麼我感覺不到了……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"언제 얼어붙은 거지……!?","JPN":"いつの間に、凍りついたの……！？","ENG":"When did they freeze...?!","TWN":"究竟是什麼時候……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼 그렇지.","JPN":"そりゃ、そうよ。","ENG":"I knew it.","TWN":"我知道你們。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"연주에 몰두하느라 주변을 살필 겨를도 없었구나?","JPN":"演奏に夢中で、周りを見る余裕もなかったもの。","ENG":"You were so preoccupied in performing that you failed to see around you.","TWN":"因為太專注於演奏而沒有時間環顧四周。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"크윽……!! 이게 대체……!?","JPN":"くっ……！！　これはいったい……！？","ENG":"Kgh...!! What is this...?!","TWN":"呃啊……！！這到底……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그거 내 카운터 능력이야.","JPN":"それが私のカウンター能力よ。","ENG":"It's my Counter ability.","TWN":"這就是我的制裁者能力。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 생성한 얼음은 주위의 온도를 계속해서 빼앗거든. 대상이 완전히 얼어붙을 때까지.","JPN":"私が作り出した氷は周りの温度を奪い続けるの。対象が完全に凍りつくまでね。","ENG":"The ice I create continues to lower the surrounding's temperature until the target is completely frozen.","TWN":"我製造的冰晶會持續地竊取周圍的溫度。直到目標完全凍結。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 애초부터 널 맞출 생각이 없었던 거야.","JPN":"最初からあなたに当てるつもりなんかなかったってこと。","ENG":"That's why I had no intention of aiming directly at you.","TWN":"所以我從一開始就沒打算射中你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 눈치채지 못하도록…… 손끝과 발끝부터 최대한 천천히 얼려야 했으니까.","JPN":"あなたに気づかれないように……指と足の先からなるべくゆっくり凍らせる必要があったからね。","ENG":"So that you wouldn't notice... you were slowly freezing away from head to toe.","TWN":"為防止你察覺，我從你的指尖和腳趾開始，盡可能減緩了凍結的速度。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"자, 잠깐만……!!","JPN":"ちょ、ちょっと待って……！！","ENG":"W-wait...!!","TWN":"等、等等……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그거 알아?","JPN":"ねえ、知ってる？","ENG":"Did you know?","TWN":"你知道嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"원래 환상종 카운터는 엘리시움 그림자와 상성이 좋지 않아.","JPN":"幻想種のカウンターは元々、エリシウムのシャドウと相性が悪いの。","ENG":"Bygone Counters are inherently disadvantaged against Elysium Shadows.","TWN":"樂團的暗影原本是克制夢幻品種制裁者的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 동물적인 초감각 때문에 오히려 음파를 이용한 정신 공격에 매우 취약하거든.","JPN":"動物的な超感覚のせいで、音波を利用した精神攻撃に弱いのよね。","ENG":"Our animal-like senses make us very susceptible to your sonic mental attacks.","TWN":"我們擁有類似動物的超感應，因此很容易受到聲波的精神攻擊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 엘리시움 그림자를 최초 관측한 우리 야크샤는 너희에게 수많은 전대원들을 잃었어.","JPN":"だからエリシウムのシャドウに初めて遭遇した私たちヤクシャーは、あなたたちにたくさんの仲間を殺された。","ENG":"That's why the Yaksha Division lost a lot of good members when we first discovered Elysium Shadows.","TWN":"所以，我們夜叉，最先觀察到愛樂組織的暗影時，失去了很多寶貴的隊員。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그들의 목숨값을 지불하고 나서야…… 우리는 비로소 알 수 있었지.","JPN":"彼らの命を犠牲にした後……ようやく気づいたの。","ENG":"It was only after we paid the hefty price that... we figured it out.","TWN":"在付出了生命的代價之後……我們才知道。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"연주에 집착해서 상대를 괴롭히려는 성향 자체가…… 너희가 가진 결함이라는 걸.","JPN":"演奏に執着し、相手を苦しめようとする性質そのものが、あなたたちの欠陥ってことにね。","ENG":"Your obsession for tormenting others with your performances itself is... the flaw that you all have.","TWN":"沉迷於演奏和戲耍他人……是你們的破綻。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결국, 지휘자가 없이는 그저 악기의 망집에 취한 괴물이라는 거야.","JPN":"指揮者がいないあなたたちは、楽器の妄執に囚われた化け物にすぎない。","ENG":"Eventually, you're all just monsters absorbed by your instruments when the conductor isn't around.","TWN":"以及，如果沒有指揮家，你們不過世沉溺於樂器中的怪物而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"시, 싫어……!! 싫다고……!!","JPN":"い、嫌……！！　嫌よ……！！","ENG":"N-no...! NO...!!","TWN":"不、不要……！！不要……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"내, 내 손가락이 전부 떨어져 버렸어……!! 이래서는 연주를……!!","JPN":"私の……私の指が全部切り落とされてしまったわ……！！　これでは演奏が……！！","ENG":"A-all my fingers are gone...! I can't perform...!!","TWN":"我的手指都掉了……！！這樣就不能演奏了……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"다리도…… 두 다리가 다시…… 움직이지 않아……!!","JPN":"足も……足もまた……動けなくなった……！！","ENG":"My legs... I can't move... either of them...!!","TWN":"腿……兩條腿都……動不了了……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어떻게 얻은 기회인데……!! 두 번 다시 얻을 수 없는 기회인데……!!","JPN":"やっと手に入れたチャンスなのに……！！　こんなチャンス、もう二度とないというのに……！！","ENG":"This was my chance...! My last chance...!!","TWN":"我好不容易得到的機會……！！這種機會不會有第二次了……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그, 그렇지! 얘기를 해보자……! 관리국이 원하는 정보라면 뭐든지 넘길게……!!","JPN":"そ、そうだわ……！　話し合いましょう……！　管理局が望む情報なら、なんでも教えるわ……！！","ENG":"R-right! Let's talk...! I'll give you any information the Administration wants...!!","TWN":"對、對了！我們談談吧……！管理局想要什麼資訊我都會告訴你……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"혹시 미래에 대해서 궁금하지……!","JPN":"未来について知りたくな……！","ENG":"Aren't you curious about the future...?","TWN":"你就不好奇自己的未來嗎……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"으악……!! 내 눈이……!!","JPN":"あああ……！！　目が……！！","ENG":"AAARGH...!! My eyes...!","TWN":"呃……呃啊啊！！我的眼睛……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어때? 안구가 속부터 얼어붙는 기분은?","JPN":"どう？　眼球が内側から凍りつく感覚は。","ENG":"What's it like having your eyes freeze from the inside?","TWN":"如何？是不是感覺眼球從內到外都結冰了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"내 아름다운 눈이……!!","JPN":"私の美しい目が……！！","ENG":"My beautiful eyes...!!","TWN":"我美麗的眼睛……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"차, 차라리 죽여……!! 죽여달라고……!! 제발……!!","JPN":"こ、殺して……！！　いっそのこと殺してちょうだい……！！　お願い……！！","ENG":"J-just kill me...! KILL ME...!! Please...!!","TWN":"還不快殺了我……！！求你殺了我……！！殺了我……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"동포들의 머릿속을 헤집어서 장난감처럼 가지고 놀 때는 언제고 잘도 짖어대는 구나?","JPN":"私たちの同胞の精神をおもちゃのように弄んでいたくせに、よく言うのね。","ENG":"Look at you beg after enjoying tormenting my compatriots' minds like they were your toys.","TWN":"你不是喜歡玩弄我們同伴的思緒，把他們當作玩具一樣對待，現在就輪到自己了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"크윽, 제발……! 제발 죽여줘……!!","JPN":"くうっ……！　お願いだから……！　殺して……！！","ENG":"Kgh, please...! Just end me...!!","TWN":"咳呃，求求你……！殺了我吧……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 그런데 어쩌나?","JPN":"うーん、でも残念。","ENG":"Hmm, but you know what?","TWN":"嗯，可是抱歉？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"미안하지만, 널 죽이는 건 내가 아니거든.","JPN":"悪いけど、あなたを殺すのは私の役目じゃないの。","ENG":"I'm sorry to tell you this, but I'm not the one who's going to kill you.","TWN":"要殺你的人不是我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……앨리스 브레이드우드 대원.","JPN":"……アリス・ブレイドウッド隊員。","ENG":"...Alice Braidwood.","TWN":"……艾莉絲·布雷德伍德隊員。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"앞으로.","JPN":"前へ。","ENG":"Step forward.","TWN":"出列。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어, 어어? 나……?","JPN":"え、ええ？　アタシ……？","ENG":"H-huh?? Me...?","TWN":"啊、啊啊？我……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"본의 아니게 내가 도와주는 모양세가 됐지만, 신고식의 마무리는 본인이 지어야지.","JPN":"手伝わせるような形になってしまったけど、通過儀礼なんだから自分の手で止めを刺さないとね。","ENG":"Though I may have unintentionally helped you, it's you who should finish your debut.","TWN":"我也許無意中幫了忙，但出道需要你自己來完成。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자기에게 이끌린 그림자는 스스로 끊어낸다.","JPN":"自分に付きまとうシャドウは、自分で断ち切るしかない。","ENG":"Defeat the Shadow that's attracted to you with your own hands.","TWN":"斬斷被自己吸引的暗影。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 야크샤의 전통이니까.","JPN":"それがヤクシャーの伝統よ。","ENG":"That's Yaksha's tradition.","TWN":"是夜叉的傳統。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"으아…… 으아악!! 빨리……!!","JPN":"ああ……あああ！！　早く……！！","ENG":"Aaah... Aaack...!! Hurry...!!","TWN":"呃啊……呃啊啊……！！快點……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아무든 좋으니까……!! 빨리 나를 죽여달라고!!","JPN":"誰でもいいから……！！　早く私を殺して！！","ENG":"I don't care who does it...!! Just end my suffering!!","TWN":"什麼都好……！！請快點殺了我吧！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"망설이지 마. 앨리스.","JPN":"ためらわないで、アリス。","ENG":"Don't hesitate, Alice.","TWN":"不要猶豫。艾莉絲。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 녀석들은 인간의 탈을 쓴 그림자. 인류의 적일 뿐이야.","JPN":"こいつらは人間の皮を被ったシャドウ。人類の敵よ。","ENG":"Shadows are monsters disguised as humans. They're our enemy.","TWN":"這些傢伙是暗影。他們是人類的敵人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다시는 눈앞에서 누군가가 죽는 꼴을 보고 싶지 않다고 했지?","JPN":"もう二度と目の前で誰かを死なせたくないって、言ってたでしょう？","ENG":"You said you didn't want to see anyone die anymore, right?","TWN":"你說過你再也不想看到有人死在你面前，對嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 녀석들은 눈 하나 깜짝하지 않고, 네 소중한 사람들을 죽일 거야.","JPN":"こいつらを生かしておくと、あなたの大事な人々を平気で殺していくよ。","ENG":"Well, these monsters kill without even batting an eye. They'll come for your loved ones.","TWN":"這些傢伙殺死你最重要的人，就連眼睛都不會眨一下。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"<color=#ff3636>아으윽……!! 아파……!! 아프다고……!!</color>","JPN":"<color=#ff3636>あうう……！！　痛い……！！　痛いわ……！！</color>","ENG":"<color=#ff3636>AAAGH...! It hurts...! IT HURTS...!!</color>","TWN":"<color=#ff3636>啊啊……！！好痛……！！好痛……！！</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"<color=#ff3636>뭘 망설이고 있어……!! 빨리 죽여……!! 죽여달라고……!!</color>","JPN":"<color=#ff3636>何を迷っている……！！　早く殺しなさい……！！　殺してよ……！！</color>","ENG":"<color=#ff3636>WHAT ARE YOU WAITING FOR...?! KILL ME...!! KILL ME!!</color>","TWN":"<color=#ff3636>你還猶豫什麼……！！快點殺了我吧……！！求你殺了我……！！</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"<color=#ff3636>앨리스 브레이드우드──────!!</color>","JPN":"<color=#ff3636>アリス・ブレイドウッド─────！！</color>","ENG":"<color=#ff3636>ALICE BRAIDWOOD!!</color>","TWN":"<color=#ff3636>艾莉絲·布雷德伍德──────！！</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"도플갱어 타입 그림자는 원본이 되는 사람이 복제되어 만들어진다고 했지?","JPN":"ドッペルシャドウは、オリジナルを複製して生まれるって言ってたよな。","ENG":"You said that Doppelganger-type Shadows are clones of the original person, right?","TWN":"你說二重身型暗影是透過複製本體而產生的吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나랑 똑같이 생긴 녀석을 죽이게 될 줄이야…….","JPN":"自分そっくりのやつを殺すことになるとは……","ENG":"I never thought I'd kill someone who looks exactly like me...","TWN":"我從來沒想過我會殺死一個和我長得一模一樣的人……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길, 기분 더럽다고, 이거.","JPN":"くそ、胸糞悪いな。","ENG":"Dammit, this feels horrible.","TWN":"可惡，這種感覺糟透了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 기분, 앞으로도 잘 기억해 둬.","JPN":"その感覚、覚えておいてね。","ENG":"Don't forget how you feel today.","TWN":"這種感覺，以後也請好好記住吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국의 일원으로서 세계를 지킨다는 건, 그런 거니까.","JPN":"管理局の一員として世界を守るというのは、そういうことよ。","ENG":"Because that's what it means to be in the Administration and save the world.","TWN":"這就是身為管理局的一員，守護世界的感覺。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};